PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE images (
    id       INTEGER PRIMARY KEY AUTOINCREMENT,
    slug     TEXT NOT NULL,
    type     TEXT NOT NULL,
    filename TEXT NOT NULL,
    caption  TEXT,
    created  TEXT NOT NULL DEFAULT (datetime('now'))
  );
CREATE TABLE plans (
    id      TEXT PRIMARY KEY,
    data    TEXT NOT NULL,
    updated TEXT NOT NULL DEFAULT (datetime('now'))
  );
CREATE TABLE observations (
    id       INTEGER PRIMARY KEY AUTOINCREMENT,
    garden   TEXT NOT NULL DEFAULT 'betonbeete',
    date     TEXT,
    type     TEXT NOT NULL DEFAULT 'foto',
    text     TEXT,
    filename TEXT,
    created  TEXT NOT NULL DEFAULT (datetime('now'))
  );
CREATE TABLE observation_plants (
    observation_id INTEGER NOT NULL REFERENCES observations(id) ON DELETE CASCADE,
    slug           TEXT NOT NULL,
    PRIMARY KEY (observation_id, slug)
  );
CREATE TABLE custom_plants (
    slug     TEXT PRIMARY KEY,
    name     TEXT NOT NULL,
    name_de  TEXT,
    family   TEXT,
    color    TEXT,
    world_w  REAL NOT NULL DEFAULT 0.5,
    world_h  REAL NOT NULL DEFAULT 1.0,
    garden   TEXT NOT NULL DEFAULT 'betonbeete',
    created  TEXT NOT NULL DEFAULT (datetime('now'))
  );
CREATE TABLE plant_info (
    slug    TEXT PRIMARY KEY,
    art     TEXT,
    wuchs   TEXT,
    hoehe   TEXT,
    breite  TEXT,
    frost   TEXT,
    wurzel  TEXT,
    updated TEXT NOT NULL DEFAULT (datetime('now'))
  , licht TEXT, boden TEXT, wasser TEXT, naehrstoff TEXT, ph TEXT, kuebel TEXT, bloom_months TEXT, invasiv TEXT);
CREATE TABLE bed_images (
    id        INTEGER PRIMARY KEY AUTOINCREMENT,
    garden    TEXT NOT NULL DEFAULT 'betonbeete',
    bed_index INTEGER NOT NULL,
    filename  TEXT NOT NULL,
    created   TEXT NOT NULL DEFAULT (datetime('now')),
    UNIQUE(garden, bed_index)
  );
COMMIT;
